// app/api/health/route.ts
export const runtime = 'edge'  // OK

export async function GET() {
  // Web APIs only:
  const res = await fetch('https://api.example.com/ping')
  return Response.json({ ok: res.ok })
}

Allow-list APIs used: fetch, Response, Request, URL, crypto.subtle.

// app/api/upload/route.ts
import fs from 'fs/promises'              // NODE-only
export const runtime = 'edge'              // declares Edge

export async function POST(req: Request) {
  const buf = await req.arrayBuffer()
  await fs.writeFile('/tmp/upload', Buffer.from(buf))  // boom
  return Response.json({ ok: true })
}

Local: works (Node fs available).
Production: 500. Edge runtime has no fs.
